input.content:
"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ── Internal context types ─────────────────────────────────────────────────────

interface StepperContextValue {
  activeStep: number
  onStepChange: (step: number) => void
  orientation: "horizontal" | "vertical"
  totalSteps: number
}

interface StepperItemContextValue {
  step: number
  state: "active" | "completed" | "inactive"
}

// ── Contexts ───────────────────────────────────────────────────────────────────

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepperContext(): StepperContextValue {
  const ctx = React.useContext(StepperContext)
  if (!ctx) {
    throw new Error("Stepper sub-components must be rendered inside <Stepper />")
  }
  return ctx
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItemContext(): StepperItemContextValue {
  const ctx = React.useContext(StepperItemContext)
  if (!ctx) {
    throw new Error(
      "StepperTrigger, StepperTitle, StepperDescription, and StepperSeparator must be rendered inside <StepperItem />"
    )
  }
  return ctx
}

// ── Stepper ────────────────────────────────────────────────────────────────────

interface StepperProps extends React.HTMLAttributes<HTMLDivElement> {
  /**
   * The currently active step (1-based). Use with `onStepChange` for
   * controlled mode.
   */
  activeStep?: number
  /**
   * The initial active step for uncontrolled mode. Defaults to `1`.
   */
  defaultStep?: number
  /**
   * Called when the user clicks a step trigger.
   */
  onStepChange?: (step: number) => void
  /**
   * Layout direction of the step indicators. Defaults to `"horizontal"`.
   */
  orientation?: "horizontal" | "vertical"
  /**
   * Total number of steps — forwarded to triggers as `aria-setsize`.
   */
  totalSteps: number
}

function Stepper({
  activeStep: activeStepProp,
  defaultStep = 1,
  onStepChange,
  orientation = "horizontal",
  totalSteps,
  className,
  ...props
}: StepperProps) {
  const [uncontrolledStep, setUncontrolledStep] = React.useState(defaultStep)
  const isControlled = activeStepProp !== undefined
  const activeStep = isControlled ? activeStepProp : uncontrolledStep

  const handleStepChange = React.useCallback(
    (step: number) => {
      if (!isControlled) setUncontrolledStep(step)
      onStepChange?.(step)
    },
    [isControlled, onStepChange]
  )

  return (
    <StepperContext.Provider
      value={{ activeStep, onStepChange: handleStepChange, orientation, totalSteps }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("flex flex-col gap-6", className)}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ── StepperItem ────────────────────────────────────────────────────────────────

interface StepperItemProps extends React.HTMLAttributes<HTMLDivElement> {
  /**
   * The 1-based step number this item represents.
   */
  step: number
}

function StepperItem({ step, className, ...props }: StepperItemProps) {
  const { activeStep, orientation } = useStepperContext()

  const state: "active" | "completed" | "inactive" =
    step < activeStep ? "completed" : step === activeStep ? "active" : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        className={cn(
          "group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-1 flex-row items-start"
            : "flex-col",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ── StepperTrigger ─────────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onStepChange, orientation, totalSteps } = useStepperContext()
  const { step, state } = useStepperItemContext()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      type="button"
      role="tab"
      aria-selected={state === "active"}
      aria-posinset={step}
      aria-setsize={totalSteps}
      onClick={() => onStepChange(step)}
      className={cn(
        "group/stepper-trigger flex shrink-0 rounded-md text-left transition-all",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        orientation === "horizontal"
          ? "flex-col items-center gap-1.5"
          : "flex-row items-start gap-3",
        className
      )}
      {...props}
    >
      {/* Step indicator circle */}
      <span
        data-slot="stepper-indicator"
        className={cn(
          "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-all",
          state === "completed" &&
            "border-primary bg-primary text-primary-foreground",
          state === "active" &&
            "border-primary bg-background text-primary ring-4 ring-primary/20",
          state === "inactive" &&
            "border-muted-foreground/30 bg-muted text-muted-foreground"
        )}
      >
        {state === "completed" ? (
          <CheckIcon className="size-4" aria-hidden="true" />
        ) : (
          <span aria-hidden="true">{step}</span>
        )}
      </span>
      {/* Slot for StepperTitle and StepperDescription */}
      {children && (
        <div
          className={cn(
            "flex flex-col gap-0.5",
            orientation === "horizontal"
              ? "items-center text-center"
              : "items-start text-left"
          )}
        >
          {children}
        </div>
      )}
    </button>
  )
}

// ── StepperTitle ───────────────────────────────────────────────────────────────

function StepperTitle({
  className,
  ...props
}: React.HTMLAttributes<HTMLParagraphElement>) {
  const { state } = useStepperItemContext()

  return (
    <p
      data-slot="stepper-title"
      className={cn(
        "text-sm font-medium leading-none transition-colors",
        state === "active" ? "text-foreground" : "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ── StepperDescription ─────────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.HTMLAttributes<HTMLParagraphElement>) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ── StepperSeparator ───────────────────────────────────────────────────────────

/**
 * A decorative connector line placed after a step trigger.
 *
 * When rendered inside a `<StepperItem />` the line is automatically colored
 * to reflect that step's completion state. When placed outside a
 * `<StepperItem />` it always renders in the default border color.
 */
function StepperSeparator({
  className,
  ...props
}: React.HTMLAttributes<HTMLDivElement>) {
  const { orientation } = useStepperContext()
  // useContext (not the throwing helper) so this component can be used both
  // inside and outside a StepperItem.
  const itemCtx = React.useContext(StepperItemContext)
  const state = itemCtx?.state

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      aria-hidden="true"
      className={cn(
        "shrink-0 transition-colors duration-300",
        state === "completed" ? "bg-primary" : "bg-border",
        orientation === "horizontal"
          ? "mt-4 h-0.5 min-w-8 flex-1"
          : "ms-[15px] mt-1 w-0.5 min-h-6",
        className
      )}
      {...props}
    />
  )
}

// ── StepperPanel ───────────────────────────────────────────────────────────────

interface StepperPanelProps extends React.HTMLAttributes<HTMLDivElement> {
  /**
   * The 1-based step number this panel belongs to. The panel only mounts
   * when this matches the current active step.
   */
  step: number
}

function StepperPanel({
  step,
  className,
  children,
  ...props
}: StepperPanelProps) {
  const { activeStep } = useStepperContext()

  if (step !== activeStep) return null

  return (
    <div
      data-slot="stepper-panel"
      role="tabpanel"
      tabIndex={0}
      className={cn("outline-none", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ── Exports ────────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
}

